import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { sendOtp, verifyOtp } from "../services/api"; // ✅ Correct path
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
} from "@mui/material";

export default function UserLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  // Step 1: Send OTP
  const handleSendOtp = async () => {
    setError(""); setSuccess("");
    if (!mobile || mobile.length !== 10) {
      setError("Enter a valid 10-digit mobile number");
      return;
    }
    try {
      setLoading(true);
      const res = await sendOtp(mobile, "user");
      if (res.data.success) {
        setSuccess(`OTP sent! Check terminal (OTP: ${res.data.otp})`);
        setStep(2);
      } else {
        setError(res.data.message || "Failed to send OTP");
      }
    } catch (err) {
      setError("Server error while sending OTP");
    } finally {
      setLoading(false);
    }
  };

  // Step 2: Verify OTP
  const handleVerifyOtp = async () => {
    setError(""); setSuccess("");
    if (!otp || otp.length < 4) {
      setError("Enter a valid OTP");
      return;
    }
    try {
      setLoading(true);
      const res = await verifyOtp(mobile, otp, "user");

      if (res.data.success) {
        // Save real token from backend
        localStorage.setItem("token", res.data.token);
        localStorage.setItem("role", "user");

        setSuccess("Login successful! Redirecting...");
        setTimeout(() => navigate("/user-dashboard"), 500);
      } else {
        setError(res.data.message || "Invalid OTP");
      }
    } catch (err) {
      setError("Server error while verifying OTP");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Box sx={{ mt: 8, p: 4, border: "1px solid #ccc", borderRadius: 2, textAlign: "center" }}>
        <Typography variant="h5" gutterBottom>
          User Login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        {step === 1 ? (
          <>
            <TextField fullWidth label="Mobile Number" value={mobile} onChange={e => setMobile(e.target.value)} margin="normal" />
            <Button fullWidth variant="contained" onClick={handleSendOtp} disabled={loading} sx={{ mt: 2, bgcolor: "black" }}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          </>
        ) : (
          <>
            <TextField fullWidth label="Enter OTP" value={otp} onChange={e => setOtp(e.target.value)} margin="normal" />
            <Button fullWidth variant="contained" onClick={handleVerifyOtp} disabled={loading} sx={{ mt: 2, bgcolor: "black" }}>
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Box sx={{ mt: 3 }}>
          <Typography variant="body2">
            Don’t have an account? <Link to="/register" style={{ fontWeight: "bold" }}>Sign up</Link>
          </Typography>
          <Typography variant="body2" sx={{ mt: 1 }}>
            Are you a Rider? <Link to="/rider-login" style={{ fontWeight: "bold" }}>Login as Rider</Link>
          </Typography>
        </Box>
      </Box>
    </Container>
  );
}
